package com.example.aistudyassistance.Activity

import android.content.Intent
import android.os.Bundle
import android.view.View
import android.widget.ImageView
import android.widget.LinearLayout
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.viewpager2.widget.ViewPager2
import com.example.aistudyassistance.Flashcard
import com.example.aistudyassistance.FlashcardPagerAdapter
import com.example.aistudyassistance.MainActivity
import com.example.aistudyassistance.R
import com.google.android.material.button.MaterialButton
import com.google.android.material.progressindicator.LinearProgressIndicator

class FlashcardActivity : AppCompatActivity() {

    private lateinit var tvFlashcardTitle: TextView
    private lateinit var tvProgress: TextView
    private lateinit var progressBar: LinearProgressIndicator
    private lateinit var viewPager: ViewPager2
    private lateinit var btnPrevious: MaterialButton
    private lateinit var btnFlip: MaterialButton
    private lateinit var btnNext: MaterialButton
    private lateinit var layoutFlashcardContent: LinearLayout
    private lateinit var layoutDeckCompleted: LinearLayout
    private lateinit var tvCompletedCount: TextView
    private lateinit var btnRestartDeck: MaterialButton
    private lateinit var btnBackHome: MaterialButton

    private lateinit var adapter: FlashcardPagerAdapter
    private val flashcards = mutableListOf<Flashcard>()
    private var revealedStates = mutableListOf<Boolean>()
    private var difficultyStates = mutableListOf<Int>()

    private var source: String = FlashcardSetupActivity.SOURCE_TOPIC
    private var topicText: String = ""
    private var selectedNote: String = ""
    private var cardCount: Int = 10
    private var currentCardIndex = 0
    private var swipeHintShown = false
    private var isFlipping = false
    private var isDeckCompleted = false

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_flashcard)

        readIntentData()
        initViews()
        setupFlashcards()
        restoreState(savedInstanceState)
        setupViewPager()
        setupListeners()
        showSwipeHintOnce()
        if (isDeckCompleted) {
            showCompletionView()
        } else {
            val targetIndex = currentCardIndex.coerceIn(0, flashcards.lastIndex)
            viewPager.setCurrentItem(targetIndex, false)
            updateProgress(targetIndex)
            updateNavigationButtons(targetIndex)
        }
    }

    private fun readIntentData() {
        source = intent.getStringExtra(FlashcardSetupActivity.EXTRA_SOURCE)
            ?: FlashcardSetupActivity.SOURCE_TOPIC
        topicText = intent.getStringExtra(FlashcardSetupActivity.EXTRA_TOPIC_TEXT) ?: ""
        selectedNote = intent.getStringExtra(FlashcardSetupActivity.EXTRA_SELECTED_NOTE) ?: ""
        cardCount = intent.getIntExtra(FlashcardSetupActivity.EXTRA_CARD_COUNT, 10).coerceIn(1, 20)
    }

    private fun initViews() {
        tvFlashcardTitle = findViewById(R.id.tvFlashcardTitle)
        tvProgress = findViewById(R.id.tvFlashcardProgress)
        progressBar = findViewById(R.id.flashcardProgressBar)
        viewPager = findViewById(R.id.viewPagerFlashcards)
        btnPrevious = findViewById(R.id.btnFlashcardPrevious)
        btnFlip = findViewById(R.id.btnFlashcardFlip)
        btnNext = findViewById(R.id.btnFlashcardNext)
        layoutFlashcardContent = findViewById(R.id.layoutFlashcardContent)
        layoutDeckCompleted = findViewById(R.id.layoutDeckCompleted)
        tvCompletedCount = findViewById(R.id.tvCompletedCount)
        btnRestartDeck = findViewById(R.id.btnRestartDeck)
        btnBackHome = findViewById(R.id.btnBackHome)

        val titleName = if (source == FlashcardSetupActivity.SOURCE_TOPIC) {
            topicText.ifBlank { "General Study" }
        } else {
            selectedNote.ifBlank { "My Notes" }
        }
        tvFlashcardTitle.text = "Flashcards: $titleName"

        findViewById<ImageView>(R.id.ivBack).setOnClickListener {
            finish()
        }
    }

    private fun setupFlashcards() {
        val contextLabel = if (source == FlashcardSetupActivity.SOURCE_TOPIC) {
            topicText.ifBlank { "this topic" }
        } else {
            selectedNote.ifBlank { "your selected note" }
        }

        flashcards.clear()
        for (index in 1..cardCount) {
            flashcards.add(
                Flashcard(
                    question = "Flashcard $index question from $contextLabel",
                    answer = "This is a placeholder answer for flashcard $index."
                )
            )
        }

        revealedStates = MutableList(flashcards.size) { false }.toMutableList()
        difficultyStates = MutableList(flashcards.size) { FlashcardPagerAdapter.DIFFICULTY_NONE }.toMutableList()
    }

    private fun restoreState(savedInstanceState: Bundle?) {
        if (savedInstanceState == null) return

        currentCardIndex = savedInstanceState.getInt(KEY_CURRENT_INDEX, 0)
        swipeHintShown = savedInstanceState.getBoolean(KEY_SWIPE_HINT_SHOWN, false)
        isDeckCompleted = savedInstanceState.getBoolean(KEY_DECK_COMPLETED, false)

        savedInstanceState.getBooleanArray(KEY_REVEALED_STATES)?.let { restored ->
            restored.forEachIndexed { index, value ->
                if (index in revealedStates.indices) {
                    revealedStates[index] = value
                }
            }
        }

        savedInstanceState.getIntArray(KEY_DIFFICULTY_STATES)?.let { restored ->
            restored.forEachIndexed { index, value ->
                if (index in difficultyStates.indices) {
                    difficultyStates[index] = value
                }
            }
        }
    }

    private fun setupViewPager() {
        adapter = FlashcardPagerAdapter(
            flashcards = flashcards,
            revealedStates = revealedStates,
            difficultyStates = difficultyStates,
            onCardTapped = { position ->
                if (!isFlipping) {
                    adapter.toggleRevealState(position)
                }
            },
            onDifficultyClicked = { _, difficulty ->
                val label = when (difficulty) {
                    FlashcardPagerAdapter.DIFFICULTY_EASY -> "Easy"
                    FlashcardPagerAdapter.DIFFICULTY_MEDIUM -> "Medium"
                    FlashcardPagerAdapter.DIFFICULTY_HARD -> "Hard"
                    else -> ""
                }
                Toast.makeText(this, "$label selected", Toast.LENGTH_SHORT).show()
            },
            onFlipStateChanged = { position, flipping ->
                if (position == viewPager.currentItem) {
                    isFlipping = flipping
                    updateFlipButtonState()
                }
            }
        )

        viewPager.adapter = adapter
        viewPager.offscreenPageLimit = 1
        viewPager.registerOnPageChangeCallback(object : ViewPager2.OnPageChangeCallback() {
            override fun onPageSelected(position: Int) {
                currentCardIndex = position
                updateProgress(position)
                updateNavigationButtons(position)
                isFlipping = adapter.isCardFlipping(position)
                updateFlipButtonState()
            }
        })
    }

    private fun setupListeners() {
        btnPrevious.setOnClickListener {
            val current = viewPager.currentItem
            if (current > 0) {
                viewPager.currentItem = current - 1
            }
        }

        btnFlip.setOnClickListener {
            if (!isFlipping) {
                adapter.toggleRevealState(viewPager.currentItem)
            }
        }

        btnNext.setOnClickListener {
            val current = viewPager.currentItem
            if (current < flashcards.lastIndex) {
                viewPager.currentItem = current + 1
            } else {
                showCompletionView()
            }
        }

        btnRestartDeck.setOnClickListener {
            restartDeck()
        }

        btnBackHome.setOnClickListener {
            startActivity(
                Intent(this, MainActivity::class.java).apply {
                    addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP)
                }
            )
            finish()
        }
    }

    private fun updateProgress(position: Int) {
        val total = flashcards.size.coerceAtLeast(1)
        val current = position + 1
        tvProgress.text = "Card $current / $total"

        val progress = (current / total.toFloat())
        val percentage = (progress * 100).toInt()
        progressBar.setProgressCompat(percentage, true)
    }

    private fun updateNavigationButtons(position: Int) {
        btnPrevious.isEnabled = position > 0
        btnNext.isEnabled = true
        btnNext.alpha = 1f
        updateFlipButtonState()
    }

    private fun updateFlipButtonState() {
        val enabled = !isFlipping && !isDeckCompleted
        btnFlip.isEnabled = enabled
        btnFlip.alpha = if (enabled) 1f else 0.6f
    }

    private fun showSwipeHintOnce() {
        if (swipeHintShown) return
        Toast.makeText(this, "Swipe left or right to navigate cards →", Toast.LENGTH_SHORT).show()
        swipeHintShown = true
    }

    private fun showCompletionView() {
        isDeckCompleted = true
        layoutFlashcardContent.visibility = View.GONE
        layoutDeckCompleted.visibility = View.VISIBLE
        tvCompletedCount.text = "Total cards reviewed: ${flashcards.size}"
        updateFlipButtonState()
    }

    private fun restartDeck() {
        isDeckCompleted = false
        revealedStates = MutableList(flashcards.size) { false }.toMutableList()
        difficultyStates = MutableList(flashcards.size) { FlashcardPagerAdapter.DIFFICULTY_NONE }.toMutableList()
        currentCardIndex = 0
        isFlipping = false

        adapter = FlashcardPagerAdapter(
            flashcards = flashcards,
            revealedStates = revealedStates,
            difficultyStates = difficultyStates,
            onCardTapped = { position ->
                if (!isFlipping) {
                    adapter.toggleRevealState(position)
                }
            },
            onDifficultyClicked = { _, difficulty ->
                val label = when (difficulty) {
                    FlashcardPagerAdapter.DIFFICULTY_EASY -> "Easy"
                    FlashcardPagerAdapter.DIFFICULTY_MEDIUM -> "Medium"
                    FlashcardPagerAdapter.DIFFICULTY_HARD -> "Hard"
                    else -> ""
                }
                Toast.makeText(this, "$label selected", Toast.LENGTH_SHORT).show()
            },
            onFlipStateChanged = { position, flipping ->
                if (position == viewPager.currentItem) {
                    isFlipping = flipping
                    updateFlipButtonState()
                }
            }
        )

        viewPager.adapter = adapter
        layoutDeckCompleted.visibility = View.GONE
        layoutFlashcardContent.visibility = View.VISIBLE
        viewPager.setCurrentItem(0, false)
        updateProgress(0)
        updateNavigationButtons(0)
    }

    override fun onSaveInstanceState(outState: Bundle) {
        super.onSaveInstanceState(outState)
        outState.putInt(KEY_CURRENT_INDEX, viewPager.currentItem)
        outState.putBooleanArray(KEY_REVEALED_STATES, revealedStates.toBooleanArray())
        outState.putIntArray(KEY_DIFFICULTY_STATES, difficultyStates.toIntArray())
        outState.putBoolean(KEY_SWIPE_HINT_SHOWN, swipeHintShown)
        outState.putBoolean(KEY_DECK_COMPLETED, isDeckCompleted)
    }

    companion object {
        private const val KEY_CURRENT_INDEX = "current_card_index"
        private const val KEY_REVEALED_STATES = "revealed_states"
        private const val KEY_DIFFICULTY_STATES = "difficulty_states"
        private const val KEY_SWIPE_HINT_SHOWN = "swipe_hint_shown"
        private const val KEY_DECK_COMPLETED = "deck_completed"
    }
}

package com.example.aistudyassistance.Activity

import android.content.Intent
import android.os.Handler
import android.os.Bundle
import android.os.Looper
import android.os.SystemClock
import android.view.View
import android.widget.ImageView
import android.widget.LinearLayout
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.viewpager2.widget.ViewPager2
import com.example.aistudyassistance.Flashcard
import com.example.aistudyassistance.FlashcardPagerAdapter
import com.example.aistudyassistance.MainActivity
import com.example.aistudyassistance.R
import com.google.android.material.button.MaterialButton
import com.google.android.material.button.MaterialButtonToggleGroup
import com.google.android.material.progressindicator.LinearProgressIndicator
import kotlinx.serialization.decodeFromString
import kotlinx.serialization.encodeToString
import kotlinx.serialization.json.Json

class FlashcardActivity : AppCompatActivity() {

    private lateinit var tvFlashcardTitle: TextView
    private lateinit var tvStudyModeLabel: TextView
    private lateinit var tvCardTimer: TextView
    private lateinit var tvProgress: TextView
    private lateinit var progressBar: LinearProgressIndicator
    private lateinit var viewPager: ViewPager2
    private lateinit var btnPrevious: MaterialButton
    private lateinit var btnFlip: MaterialButton
    private lateinit var btnNext: MaterialButton
    private lateinit var layoutFlashcardContent: LinearLayout
    private lateinit var layoutDeckCompleted: LinearLayout
    private lateinit var tvCompletedCount: TextView
    private lateinit var tvCompletedDifficulty: TextView
    private lateinit var tvCompletedAvgTime: TextView
    private lateinit var tvCompletedUnattempted: TextView
    private lateinit var btnRestartDeck: MaterialButton
    private lateinit var btnBackHome: MaterialButton
    private lateinit var btnReviewHardCards: MaterialButton
    private lateinit var btnReviewUnattemptedCards: MaterialButton
    private lateinit var toggleStudyMode: MaterialButtonToggleGroup
    private lateinit var btnModeQuickReview: MaterialButton
    private lateinit var btnModeActiveRecall: MaterialButton

    private lateinit var adapter: FlashcardPagerAdapter
    private val flashcards = mutableListOf<Flashcard>()
    private var revealedStates = mutableListOf<Boolean>()
    private var answerRevealedStates = mutableListOf<Boolean>()
    private var difficultyStates = mutableListOf<Int>()
    private var timeSpentMs = mutableListOf<Long>()

    private var source: String = FlashcardSetupActivity.SOURCE_TOPIC
    private var topicText: String = ""
    private var selectedNote: String = ""
    private var cardCount: Int = 10
    private var generatedFlashcards: List<Flashcard> = emptyList()
    private var activeRecallEnabled = false
    private var currentCardIndex = 0
    private var swipeHintShown = false
    private var isFlipping = false
    private var isDeckCompleted = false
    private var currentCardTimerStartMs = 0L
    private val timerHandler = Handler(Looper.getMainLooper())
    private val timerRunnable = object : Runnable {
        override fun run() {
            updateTimerText(currentCardIndex)
            timerHandler.postDelayed(this, 1000)
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_flashcard)

        readIntentData()
        initViews()
        setupFlashcards()
        restoreState(savedInstanceState)
        setupViewPager()
        setupListeners()
        showSwipeHintOnce()
        if (isDeckCompleted) {
            stopTimer()
            showCompletionView()
        } else {
            val targetIndex = currentCardIndex.coerceIn(0, flashcards.lastIndex)
            viewPager.setCurrentItem(targetIndex, false)
            updateProgress(targetIndex)
            updateNavigationButtons(targetIndex)
            startTimerForCard(targetIndex)
        }
    }

    private fun readIntentData() {
        source = intent.getStringExtra(FlashcardSetupActivity.EXTRA_SOURCE)
            ?: FlashcardSetupActivity.SOURCE_TOPIC
        topicText = intent.getStringExtra(FlashcardSetupActivity.EXTRA_TOPIC_TEXT) ?: ""
        selectedNote = intent.getStringExtra(FlashcardSetupActivity.EXTRA_SELECTED_NOTE) ?: ""
        cardCount = intent.getIntExtra(FlashcardSetupActivity.EXTRA_CARD_COUNT, 10).coerceIn(1, 20)
        activeRecallEnabled = intent.getBooleanExtra(EXTRA_ACTIVE_RECALL_MODE, false)

        val flashcardsJson = intent.getStringExtra(FlashcardSetupActivity.EXTRA_FLASHCARDS_JSON)
        generatedFlashcards = try {
            if (flashcardsJson.isNullOrBlank()) {
                emptyList()
            } else {
                Json.decodeFromString(flashcardsJson)
            }
        } catch (_: Exception) {
            emptyList()
        }

        if (generatedFlashcards.isNotEmpty()) {
            cardCount = generatedFlashcards.size
        }
    }

    private fun initViews() {
        tvFlashcardTitle = findViewById(R.id.tvFlashcardTitle)
        tvStudyModeLabel = findViewById(R.id.tvStudyModeLabel)
        tvCardTimer = findViewById(R.id.tvCardTimer)
        tvProgress = findViewById(R.id.tvFlashcardProgress)
        progressBar = findViewById(R.id.flashcardProgressBar)
        viewPager = findViewById(R.id.viewPagerFlashcards)
        btnPrevious = findViewById(R.id.btnFlashcardPrevious)
        btnFlip = findViewById(R.id.btnFlashcardFlip)
        btnNext = findViewById(R.id.btnFlashcardNext)
        layoutFlashcardContent = findViewById(R.id.layoutFlashcardContent)
        layoutDeckCompleted = findViewById(R.id.layoutDeckCompleted)
        tvCompletedCount = findViewById(R.id.tvCompletedCount)
        tvCompletedDifficulty = findViewById(R.id.tvCompletedDifficulty)
        tvCompletedAvgTime = findViewById(R.id.tvCompletedAvgTime)
        tvCompletedUnattempted = findViewById(R.id.tvCompletedUnattempted)
        btnRestartDeck = findViewById(R.id.btnRestartDeck)
        btnBackHome = findViewById(R.id.btnBackHome)
        btnReviewHardCards = findViewById(R.id.btnReviewHardCards)
        btnReviewUnattemptedCards = findViewById(R.id.btnReviewUnattemptedCards)
        toggleStudyMode = findViewById(R.id.toggleStudyMode)
        btnModeQuickReview = findViewById(R.id.btnModeQuickReview)
        btnModeActiveRecall = findViewById(R.id.btnModeActiveRecall)

        val titleName = if (source == FlashcardSetupActivity.SOURCE_TOPIC) {
            topicText.ifBlank { "General Study" }
        } else {
            selectedNote.ifBlank { "My Notes" }
        }
        tvFlashcardTitle.text = "Flashcards: $titleName"
        updateStudyModeSelection()

        findViewById<ImageView>(R.id.ivBack).setOnClickListener {
            finish()
        }
    }

    private fun setupFlashcards() {
        flashcards.clear()
        if (generatedFlashcards.isNotEmpty()) {
            flashcards.addAll(generatedFlashcards)
        } else {
            val contextLabel = if (source == FlashcardSetupActivity.SOURCE_TOPIC) {
                topicText.ifBlank { "this topic" }
            } else {
                selectedNote.ifBlank { "your selected note" }
            }

            for (index in 1..cardCount) {
                flashcards.add(
                    Flashcard(
                        question = "Flashcard $index question from $contextLabel",
                        answer = "This is a placeholder answer for flashcard $index."
                    )
                )
            }
        }

        if (flashcards.isEmpty()) {
            flashcards.add(
                Flashcard(
                    question = "Flashcard generation failed",
                    answer = "Please go back and try again."
                )
            )
        }

        cardCount = flashcards.size

        revealedStates = MutableList(flashcards.size) { false }.toMutableList()
        answerRevealedStates = MutableList(flashcards.size) { false }.toMutableList()
        difficultyStates = MutableList(flashcards.size) { FlashcardPagerAdapter.DIFFICULTY_NONE }.toMutableList()
        timeSpentMs = MutableList(flashcards.size) { 0L }.toMutableList()
    }

    private fun restoreState(savedInstanceState: Bundle?) {
        if (savedInstanceState == null) return

        currentCardIndex = savedInstanceState.getInt(KEY_CURRENT_INDEX, 0)
        swipeHintShown = savedInstanceState.getBoolean(KEY_SWIPE_HINT_SHOWN, false)
        isDeckCompleted = savedInstanceState.getBoolean(KEY_DECK_COMPLETED, false)
        activeRecallEnabled = savedInstanceState.getBoolean(KEY_ACTIVE_RECALL, activeRecallEnabled)
        updateStudyModeSelection()

        savedInstanceState.getBooleanArray(KEY_REVEALED_STATES)?.let { restored ->
            restored.forEachIndexed { index, value ->
                if (index in revealedStates.indices) {
                    revealedStates[index] = value
                }
            }
        }

        savedInstanceState.getIntArray(KEY_DIFFICULTY_STATES)?.let { restored ->
            restored.forEachIndexed { index, value ->
                if (index in difficultyStates.indices) {
                    difficultyStates[index] = value
                }
            }
        }

        savedInstanceState.getBooleanArray(KEY_ANSWER_REVEALED_STATES)?.let { restored ->
            restored.forEachIndexed { index, value ->
                if (index in answerRevealedStates.indices) {
                    answerRevealedStates[index] = value
                }
            }
        }

        savedInstanceState.getLongArray(KEY_TIME_SPENT_MS)?.let { restored ->
            restored.forEachIndexed { index, value ->
                if (index in timeSpentMs.indices) {
                    timeSpentMs[index] = value
                }
            }
        }

        if (!activeRecallEnabled) {
            revealedStates.forEachIndexed { index, revealed ->
                if (revealed && index in answerRevealedStates.indices) {
                    answerRevealedStates[index] = true
                }
            }
        }
    }

    private fun setupViewPager() {
        adapter = FlashcardPagerAdapter(
            flashcards = flashcards,
            revealedStates = revealedStates,
            answerRevealedStates = answerRevealedStates,
            difficultyStates = difficultyStates,
            isActiveRecallEnabled = { activeRecallEnabled },
            onCardTapped = { position ->
                if (!isFlipping) {
                    adapter.toggleRevealState(position)
                }
            },
            onShowAnswerClicked = { position ->
                if (position == currentCardIndex) {
                    stopTimerForCard(position)
                }
            },
            onDifficultyClicked = { _, _ -> },
            onAnswerRevealed = { position ->
                if (position == currentCardIndex) {
                    stopTimerForCard(position)
                }
            },
            onFlipStateChanged = { position, flipping ->
                if (position == viewPager.currentItem) {
                    isFlipping = flipping
                    updateFlipButtonState()
                }
            }
        )

        viewPager.adapter = adapter
        viewPager.offscreenPageLimit = 1
        viewPager.registerOnPageChangeCallback(object : ViewPager2.OnPageChangeCallback() {
            override fun onPageSelected(position: Int) {
                if (currentCardIndex in timeSpentMs.indices) {
                    stopTimerForCard(currentCardIndex)
                }
                currentCardIndex = position
                updateProgress(position)
                updateNavigationButtons(position)
                isFlipping = adapter.isCardFlipping(position)
                updateFlipButtonState()
                startTimerForCard(position)
            }
        })
    }

    private fun setupListeners() {
        toggleStudyMode.addOnButtonCheckedListener { _, checkedId, isChecked ->
            if (!isChecked) return@addOnButtonCheckedListener
            val selectedActiveRecall = checkedId == R.id.btnModeActiveRecall
            applyStudyMode(selectedActiveRecall)
        }

        btnPrevious.setOnClickListener {
            val current = viewPager.currentItem
            if (current > 0) {
                viewPager.currentItem = current - 1
            }
        }

        btnFlip.setOnClickListener {
            if (!isFlipping) {
                adapter.toggleRevealState(viewPager.currentItem)
            }
        }

        btnNext.setOnClickListener {
            val current = viewPager.currentItem
            if (current < flashcards.lastIndex) {
                viewPager.currentItem = current + 1
            } else {
                showCompletionView()
            }
        }

        btnRestartDeck.setOnClickListener {
            restartDeck()
        }

        btnReviewHardCards.setOnClickListener {
            reviewHardCards()
        }

        btnReviewUnattemptedCards.setOnClickListener {
            reviewUnattemptedCards()
        }

        btnBackHome.setOnClickListener {
            startActivity(
                Intent(this, MainActivity::class.java).apply {
                    addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP)
                }
            )
            finish()
        }
    }

    private fun updateProgress(position: Int) {
        val total = flashcards.size.coerceAtLeast(1)
        val current = position + 1
        tvProgress.text = "Card $current / $total"

        val progress = (current / total.toFloat())
        val percentage = (progress * 100).toInt()
        progressBar.setProgressCompat(percentage, true)
    }

    private fun updateNavigationButtons(position: Int) {
        btnPrevious.isEnabled = position > 0
        btnNext.isEnabled = true
        btnNext.alpha = 1f
        updateFlipButtonState()
    }

    private fun updateFlipButtonState() {
        val enabled = !isFlipping && !isDeckCompleted
        btnFlip.isEnabled = enabled
        btnFlip.alpha = if (enabled) 1f else 0.6f
    }

    private fun updateStudyModeSelection() {
        val selectedId = if (activeRecallEnabled) R.id.btnModeActiveRecall else R.id.btnModeQuickReview
        if (toggleStudyMode.checkedButtonId != selectedId) {
            toggleStudyMode.check(selectedId)
        }
    }

    private fun applyStudyMode(enableActiveRecall: Boolean) {
        if (activeRecallEnabled == enableActiveRecall) return

        activeRecallEnabled = enableActiveRecall
        if (!activeRecallEnabled) {
            revealedStates.forEachIndexed { index, revealed ->
                if (revealed && !answerRevealedStates.getOrElse(index) { false }) {
                    answerRevealedStates[index] = true
                }
            }
            adapter.notifyDataSetChanged()

            if (currentCardIndex in revealedStates.indices && revealedStates[currentCardIndex]) {
                stopTimerForCard(currentCardIndex)
            }
        } else {
            adapter.notifyDataSetChanged()
        }
    }

    private fun startTimerForCard(index: Int) {
        if (index !in timeSpentMs.indices) return
        if (answerRevealedStates.getOrElse(index) { false }) {
            updateTimerText(index)
            return
        }

        stopTimer()
        currentCardTimerStartMs = SystemClock.elapsedRealtime()
        updateTimerText(index)
        timerHandler.postDelayed(timerRunnable, 1000)
    }

    private fun stopTimerForCard(index: Int) {
        if (index !in timeSpentMs.indices) {
            stopTimer()
            return
        }

        if (currentCardTimerStartMs > 0L) {
            val elapsed = SystemClock.elapsedRealtime() - currentCardTimerStartMs
            timeSpentMs[index] = timeSpentMs[index] + elapsed
        }
        stopTimer()
        updateTimerText(index)
    }

    private fun stopTimer() {
        timerHandler.removeCallbacks(timerRunnable)
        currentCardTimerStartMs = 0L
    }

    private fun getElapsedMsForCard(index: Int): Long {
        if (index !in timeSpentMs.indices) return 0L
        val base = timeSpentMs[index]
        val live = if (index == currentCardIndex && currentCardTimerStartMs > 0L) {
            SystemClock.elapsedRealtime() - currentCardTimerStartMs
        } else {
            0L
        }
        return base + live
    }

    private fun updateTimerText(index: Int) {
        val seconds = (getElapsedMsForCard(index) / 1000L).coerceAtLeast(0L)
        tvCardTimer.text = "⏱ ${seconds}s"
    }

    private fun showSwipeHintOnce() {
        if (swipeHintShown) return
        Toast.makeText(this, "Swipe left or right to navigate cards →", Toast.LENGTH_SHORT).show()
        swipeHintShown = true
    }

    private fun showCompletionView() {
        stopTimerForCard(currentCardIndex)
        isDeckCompleted = true
        tvStudyModeLabel.visibility = View.GONE
        toggleStudyMode.visibility = View.GONE
        layoutFlashcardContent.visibility = View.GONE
        layoutDeckCompleted.visibility = View.VISIBLE

        val easyCount = difficultyStates.count { it == FlashcardPagerAdapter.DIFFICULTY_EASY }
        val mediumCount = difficultyStates.count { it == FlashcardPagerAdapter.DIFFICULTY_MEDIUM }
        val hardCount = difficultyStates.count { it == FlashcardPagerAdapter.DIFFICULTY_HARD }
        val unattemptedCount = answerRevealedStates.count { !it }
        val avgSeconds = if (timeSpentMs.isEmpty()) 0 else (timeSpentMs.sum() / timeSpentMs.size) / 1000L

        tvCompletedCount.text = "Total Cards: ${flashcards.size}"
        tvCompletedDifficulty.text = "Easy: $easyCount | Medium: $mediumCount | Hard: $hardCount"
        tvCompletedAvgTime.text = "Avg Time: $avgSeconds sec"
        tvCompletedUnattempted.text = "Unattempted Cards: $unattemptedCount"
        updateFlipButtonState()
    }

    private fun reviewHardCards() {
        val hardCards = flashcards.filterIndexed { index, _ ->
            difficultyStates.getOrElse(index) { FlashcardPagerAdapter.DIFFICULTY_NONE } ==
                FlashcardPagerAdapter.DIFFICULTY_HARD
        }

        if (hardCards.isEmpty()) {
            Toast.makeText(this, "No hard cards to review", Toast.LENGTH_SHORT).show()
            return
        }

        startActivity(
            Intent(this, FlashcardActivity::class.java).apply {
                putExtra(FlashcardSetupActivity.EXTRA_SOURCE, source)
                putExtra(FlashcardSetupActivity.EXTRA_TOPIC_TEXT, topicText)
                putExtra(FlashcardSetupActivity.EXTRA_SELECTED_NOTE, selectedNote)
                putExtra(FlashcardSetupActivity.EXTRA_CARD_COUNT, hardCards.size)
                putExtra(FlashcardSetupActivity.EXTRA_FLASHCARDS_JSON, Json.encodeToString(hardCards))
                putExtra(EXTRA_ACTIVE_RECALL_MODE, activeRecallEnabled)
            }
        )
        finish()
    }

    private fun reviewUnattemptedCards() {
        val unattemptedCards = flashcards.filterIndexed { index, _ ->
            !answerRevealedStates.getOrElse(index) { false }
        }

        if (unattemptedCards.isEmpty()) {
            Toast.makeText(this, "No unattempted cards to review", Toast.LENGTH_SHORT).show()
            return
        }

        startActivity(
            Intent(this, FlashcardActivity::class.java).apply {
                putExtra(FlashcardSetupActivity.EXTRA_SOURCE, source)
                putExtra(FlashcardSetupActivity.EXTRA_TOPIC_TEXT, topicText)
                putExtra(FlashcardSetupActivity.EXTRA_SELECTED_NOTE, selectedNote)
                putExtra(FlashcardSetupActivity.EXTRA_CARD_COUNT, unattemptedCards.size)
                putExtra(FlashcardSetupActivity.EXTRA_FLASHCARDS_JSON, Json.encodeToString(unattemptedCards))
                putExtra(EXTRA_ACTIVE_RECALL_MODE, activeRecallEnabled)
            }
        )
        finish()
    }

    private fun restartDeck() {
        stopTimer()
        isDeckCompleted = false
        tvStudyModeLabel.visibility = View.VISIBLE
        toggleStudyMode.visibility = View.VISIBLE
        revealedStates = MutableList(flashcards.size) { false }.toMutableList()
        answerRevealedStates = MutableList(flashcards.size) { false }.toMutableList()
        difficultyStates = MutableList(flashcards.size) { FlashcardPagerAdapter.DIFFICULTY_NONE }.toMutableList()
        timeSpentMs = MutableList(flashcards.size) { 0L }.toMutableList()
        currentCardIndex = 0
        isFlipping = false

        adapter = FlashcardPagerAdapter(
            flashcards = flashcards,
            revealedStates = revealedStates,
            answerRevealedStates = answerRevealedStates,
            difficultyStates = difficultyStates,
            isActiveRecallEnabled = { activeRecallEnabled },
            onCardTapped = { position ->
                if (!isFlipping) {
                    adapter.toggleRevealState(position)
                }
            },
            onShowAnswerClicked = { position ->
                if (position == currentCardIndex) {
                    stopTimerForCard(position)
                }
            },
            onDifficultyClicked = { _, _ -> },
            onAnswerRevealed = { position ->
                if (position == currentCardIndex) {
                    stopTimerForCard(position)
                }
            },
            onFlipStateChanged = { position, flipping ->
                if (position == viewPager.currentItem) {
                    isFlipping = flipping
                    updateFlipButtonState()
                }
            }
        )

        viewPager.adapter = adapter
        layoutDeckCompleted.visibility = View.GONE
        layoutFlashcardContent.visibility = View.VISIBLE
        viewPager.setCurrentItem(0, false)
        updateProgress(0)
        updateNavigationButtons(0)
        startTimerForCard(0)
    }

    override fun onSaveInstanceState(outState: Bundle) {
        stopTimerForCard(currentCardIndex)
        super.onSaveInstanceState(outState)
        outState.putInt(KEY_CURRENT_INDEX, viewPager.currentItem)
        outState.putBooleanArray(KEY_REVEALED_STATES, revealedStates.toBooleanArray())
        outState.putIntArray(KEY_DIFFICULTY_STATES, difficultyStates.toIntArray())
        outState.putBooleanArray(KEY_ANSWER_REVEALED_STATES, answerRevealedStates.toBooleanArray())
        outState.putLongArray(KEY_TIME_SPENT_MS, timeSpentMs.toLongArray())
        outState.putBoolean(KEY_SWIPE_HINT_SHOWN, swipeHintShown)
        outState.putBoolean(KEY_DECK_COMPLETED, isDeckCompleted)
        outState.putBoolean(KEY_ACTIVE_RECALL, activeRecallEnabled)
    }

    override fun onDestroy() {
        stopTimer()
        super.onDestroy()
    }

    companion object {
        const val EXTRA_ACTIVE_RECALL_MODE = "activeRecallMode"
        private const val KEY_CURRENT_INDEX = "current_card_index"
        private const val KEY_REVEALED_STATES = "revealed_states"
        private const val KEY_DIFFICULTY_STATES = "difficulty_states"
        private const val KEY_ANSWER_REVEALED_STATES = "answer_revealed_states"
        private const val KEY_TIME_SPENT_MS = "time_spent_ms"
        private const val KEY_SWIPE_HINT_SHOWN = "swipe_hint_shown"
        private const val KEY_DECK_COMPLETED = "deck_completed"
        private const val KEY_ACTIVE_RECALL = "active_recall"
    }
}

package com.example.aistudyassistance.Activity

import android.content.Intent
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.view.View
import android.widget.AdapterView
import android.widget.ArrayAdapter
import android.widget.EditText
import android.widget.ImageView
import android.widget.SeekBar
import android.widget.Spinner
import android.widget.TextView
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.cardview.widget.CardView
import androidx.core.content.ContextCompat
import com.example.aistudyassistance.R
import com.google.android.material.button.MaterialButton

class FlashcardSetupActivity : AppCompatActivity() {

    private lateinit var cardTopic: CardView
    private lateinit var cardMyNotes: CardView
    private lateinit var etTopic: EditText
    private lateinit var spinnerNotes: Spinner
    private lateinit var tvSelectedNotePreview: TextView
    private lateinit var seekBarCards: SeekBar
    private lateinit var tvCardCount: TextView
    private lateinit var btnGenerateFlashcards: MaterialButton

    private var selectedSource = SOURCE_TOPIC
    private var cardCount = 10
    private var selectedNoteName = ""

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_flashcard_setup)

        initViews()
        setupPlaceholderNotes()
        setupListeners()
        updateUI()
    }

    private fun initViews() {
        cardTopic = findViewById(R.id.cardTopic)
        cardMyNotes = findViewById(R.id.cardMyNotes)
        etTopic = findViewById(R.id.etFlashcardTopic)
        spinnerNotes = findViewById(R.id.spinnerFlashcardNotes)
        tvSelectedNotePreview = findViewById(R.id.tvFlashcardSelectedNotePreview)
        seekBarCards = findViewById(R.id.seekBarFlashcardCount)
        tvCardCount = findViewById(R.id.tvFlashcardCount)
        btnGenerateFlashcards = findViewById(R.id.btnGenerateFlashcards)

        seekBarCards.max = 19
        seekBarCards.progress = 9
        tvCardCount.text = "Flashcards: 10"

        findViewById<ImageView>(R.id.ivBack).setOnClickListener {
            finish()
        }
    }

    private fun setupPlaceholderNotes() {
        val placeholderNotes = listOf(
            "Select Note",
            "Operating_System_Notes.pdf",
            "Data_Structures_Unit_2.pdf",
            "Computer_Networks_Revision.png"
        )

        val adapter = ArrayAdapter(
            this,
            android.R.layout.simple_spinner_item,
            placeholderNotes
        )
        adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item)
        spinnerNotes.adapter = adapter
    }

    private fun setupListeners() {
        cardTopic.setOnClickListener {
            selectedSource = SOURCE_TOPIC
            updateUI()
        }

        cardMyNotes.setOnClickListener {
            selectedSource = SOURCE_NOTES
            updateUI()
        }

        etTopic.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                validateInputs()
            }
            override fun afterTextChanged(s: Editable?) = Unit
        })

        spinnerNotes.onItemSelectedListener = object : AdapterView.OnItemSelectedListener {
            override fun onItemSelected(parent: AdapterView<*>, view: View?, position: Int, id: Long) {
                selectedNoteName = if (position > 0) parent.getItemAtPosition(position).toString() else ""
                tvSelectedNotePreview.text = if (selectedNoteName.isNotBlank()) {
                    "Selected Note: $selectedNoteName"
                } else {
                    "Selected Note: -"
                }
                validateInputs()
            }

            override fun onNothingSelected(parent: AdapterView<*>) {
                selectedNoteName = ""
                tvSelectedNotePreview.text = "Selected Note: -"
                validateInputs()
            }
        }

        seekBarCards.setOnSeekBarChangeListener(object : SeekBar.OnSeekBarChangeListener {
            override fun onProgressChanged(seekBar: SeekBar?, progress: Int, fromUser: Boolean) {
                cardCount = progress + 1
                tvCardCount.text = "Flashcards: $cardCount"
            }

            override fun onStartTrackingTouch(seekBar: SeekBar?) = Unit
            override fun onStopTrackingTouch(seekBar: SeekBar?) = Unit
        })

        btnGenerateFlashcards.setOnClickListener {
            val topicText = etTopic.text.toString().trim()
            val selectedNote = selectedNoteName

            val intent = Intent(this, FlashcardActivity::class.java).apply {
                putExtra(EXTRA_SOURCE, selectedSource)
                putExtra(EXTRA_TOPIC_TEXT, topicText)
                putExtra(EXTRA_SELECTED_NOTE, selectedNote)
                putExtra(EXTRA_CARD_COUNT, cardCount)
            }
            startActivity(intent)
        }
    }

    private fun updateUI() {
        val selectedColor = ContextCompat.getColor(this, R.color.primary_light)
        val defaultColor = ContextCompat.getColor(this, R.color.card_bg)

        val isTopic = selectedSource == SOURCE_TOPIC
        cardTopic.setCardBackgroundColor(if (isTopic) selectedColor else defaultColor)
        cardMyNotes.setCardBackgroundColor(if (isTopic) defaultColor else selectedColor)

        etTopic.visibility = if (isTopic) View.VISIBLE else View.GONE
        spinnerNotes.visibility = if (isTopic) View.GONE else View.VISIBLE
        tvSelectedNotePreview.visibility = if (isTopic) View.GONE else View.VISIBLE

        validateInputs()
    }

    private fun validateInputs() {
        val isValid = if (selectedSource == SOURCE_TOPIC) {
            etTopic.text.toString().trim().isNotEmpty()
        } else {
            selectedNoteName.isNotBlank()
        }

        btnGenerateFlashcards.isEnabled = isValid
        btnGenerateFlashcards.alpha = if (isValid) 1f else 0.5f
    }

    companion object {
        const val SOURCE_TOPIC = "topic"
        const val SOURCE_NOTES = "notes"

        const val EXTRA_SOURCE = "source"
        const val EXTRA_TOPIC_TEXT = "topicText"
        const val EXTRA_SELECTED_NOTE = "selectedNote"
        const val EXTRA_CARD_COUNT = "cardCount"
    }
}

package com.example.aistudyassistance.Activity

import android.app.ProgressDialog
import android.content.Intent
import android.graphics.BitmapFactory
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.view.View
import android.widget.AdapterView
import android.widget.ArrayAdapter
import android.widget.EditText
import android.widget.ImageView
import android.widget.SeekBar
import android.widget.Spinner
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AppCompatActivity
import androidx.cardview.widget.CardView
import androidx.core.content.ContextCompat
import androidx.lifecycle.lifecycleScope
import com.example.aistudyassistance.BuildConfig
import com.example.aistudyassistance.FlashcardGenerator
import com.example.aistudyassistance.GeminiHelper
import com.example.aistudyassistance.R
import com.google.android.material.button.MaterialButton
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.storage.FirebaseStorage
import com.google.mlkit.vision.common.InputImage
import com.google.mlkit.vision.text.TextRecognition
import com.google.mlkit.vision.text.latin.TextRecognizerOptions
import com.tom_roush.pdfbox.android.PDFBoxResourceLoader
import com.tom_roush.pdfbox.pdmodel.PDDocument
import com.tom_roush.pdfbox.text.PDFTextStripper
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlinx.coroutines.withContext
import kotlinx.serialization.encodeToString
import kotlinx.serialization.json.Json
import java.io.File
import kotlin.coroutines.resume

class FlashcardSetupActivity : AppCompatActivity() {

    private lateinit var cardTopic: CardView
    private lateinit var cardMyNotes: CardView
    private lateinit var etTopic: EditText
    private lateinit var spinnerNotes: Spinner
    private lateinit var tvSelectedNotePreview: TextView
    private lateinit var seekBarCards: SeekBar
    private lateinit var tvCardCount: TextView
    private lateinit var btnGenerateFlashcards: MaterialButton
    private lateinit var progressDialog: ProgressDialog
    private lateinit var flashcardGenerator: FlashcardGenerator
    private lateinit var storage: FirebaseStorage
    private lateinit var firestore: FirebaseFirestore

    private var selectedSource = SOURCE_TOPIC
    private var cardCount = 10
    private var selectedNoteName = ""
    private var selectedNote: NoteItem? = null
    private var isGenerating = false
    private val notesList = mutableListOf<NoteItem>()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_flashcard_setup)

        val apiKey = BuildConfig.apiKeySafe
        val geminiHelper = GeminiHelper(apiKey, "gemini-2.5-flash")
        flashcardGenerator = FlashcardGenerator(geminiHelper)
        storage = FirebaseStorage.getInstance()
        firestore = FirebaseFirestore.getInstance()
        PDFBoxResourceLoader.init(applicationContext)

        progressDialog = ProgressDialog(this).apply {
            setMessage("Generating Flashcards...")
            setCancelable(false)
        }

        initViews()
        setupEmptyNotesSpinner()
        setupListeners()
        updateUI()
    }

    private fun initViews() {
        cardTopic = findViewById(R.id.cardTopic)
        cardMyNotes = findViewById(R.id.cardMyNotes)
        etTopic = findViewById(R.id.etFlashcardTopic)
        spinnerNotes = findViewById(R.id.spinnerFlashcardNotes)
        tvSelectedNotePreview = findViewById(R.id.tvFlashcardSelectedNotePreview)
        seekBarCards = findViewById(R.id.seekBarFlashcardCount)
        tvCardCount = findViewById(R.id.tvFlashcardCount)
        btnGenerateFlashcards = findViewById(R.id.btnGenerateFlashcards)

        seekBarCards.max = 19
        seekBarCards.progress = 9
        tvCardCount.text = "Flashcards: 10"

        findViewById<ImageView>(R.id.ivBack).setOnClickListener {
            finish()
        }
    }

    private fun setupEmptyNotesSpinner() {
        val adapter = ArrayAdapter(this, android.R.layout.simple_spinner_item, listOf("Select Note"))
        adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item)
        spinnerNotes.adapter = adapter
    }

    private fun setupListeners() {
        cardTopic.setOnClickListener {
            selectedSource = SOURCE_TOPIC
            updateUI()
        }

        cardMyNotes.setOnClickListener {
            selectedSource = SOURCE_NOTES
            loadNotes()
            updateUI()
        }

        etTopic.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                validateInputs()
            }
            override fun afterTextChanged(s: Editable?) = Unit
        })

        spinnerNotes.onItemSelectedListener = object : AdapterView.OnItemSelectedListener {
            override fun onItemSelected(parent: AdapterView<*>, view: View?, position: Int, id: Long) {
                if (position <= 0 || notesList.isEmpty()) {
                    selectedNote = null
                    selectedNoteName = ""
                } else {
                    selectedNote = notesList[position - 1]
                    selectedNoteName = selectedNote?.name.orEmpty()
                }

                tvSelectedNotePreview.text = if (selectedNoteName.isNotBlank()) {
                    "Selected Note: $selectedNoteName"
                } else {
                    "Selected Note: -"
                }
                validateInputs()
            }

            override fun onNothingSelected(parent: AdapterView<*>) {
                selectedNoteName = ""
                tvSelectedNotePreview.text = "Selected Note: -"
                validateInputs()
            }
        }

        seekBarCards.setOnSeekBarChangeListener(object : SeekBar.OnSeekBarChangeListener {
            override fun onProgressChanged(seekBar: SeekBar?, progress: Int, fromUser: Boolean) {
                cardCount = progress + 1
                tvCardCount.text = "Flashcards: $cardCount"
            }

            override fun onStartTrackingTouch(seekBar: SeekBar?) = Unit
            override fun onStopTrackingTouch(seekBar: SeekBar?) = Unit
        })

        btnGenerateFlashcards.setOnClickListener {
            generateFlashcards()
        }
    }

    private fun updateUI() {
        val selectedColor = ContextCompat.getColor(this, R.color.primary_light)
        val defaultColor = ContextCompat.getColor(this, R.color.card_bg)

        val isTopic = selectedSource == SOURCE_TOPIC
        cardTopic.setCardBackgroundColor(if (isTopic) selectedColor else defaultColor)
        cardMyNotes.setCardBackgroundColor(if (isTopic) defaultColor else selectedColor)

        etTopic.visibility = if (isTopic) View.VISIBLE else View.GONE
        spinnerNotes.visibility = if (isTopic) View.GONE else View.VISIBLE
        tvSelectedNotePreview.visibility = if (isTopic) View.GONE else View.VISIBLE

        validateInputs()
    }

    private fun validateInputs() {
        val isValid = if (selectedSource == SOURCE_TOPIC) {
            etTopic.text.toString().trim().isNotEmpty()
        } else {
            selectedNote != null
        }

        btnGenerateFlashcards.isEnabled = isValid && !isGenerating
        btnGenerateFlashcards.alpha = if (btnGenerateFlashcards.isEnabled) 1f else 0.5f
    }

    private fun loadNotes() {
        val user = FirebaseAuth.getInstance().currentUser
        if (user == null) {
            Toast.makeText(this, "Please login to access notes", Toast.LENGTH_SHORT).show()
            return
        }

        firestore.collection("Notes")
            .document(user.uid)
            .collection("UserNotes")
            .get()
            .addOnSuccessListener { result ->
                notesList.clear()
                result.documents.forEach { doc ->
                    val name = doc.getString("name").orEmpty().trim()
                    val type = doc.getString("type").orEmpty().trim()
                    val url = doc.getString("url").orEmpty().trim()
                    if (name.isNotEmpty()) {
                        notesList.add(NoteItem(name = name, type = type, downloadUrl = url))
                    }
                }

                val spinnerItems = mutableListOf("Select Note")
                spinnerItems.addAll(notesList.map { it.name })
                if (notesList.isEmpty()) {
                    spinnerItems.add("No notes uploaded")
                }

                val adapter = ArrayAdapter(this, android.R.layout.simple_spinner_item, spinnerItems)
                adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item)
                spinnerNotes.adapter = adapter

                selectedNote = null
                selectedNoteName = ""
                tvSelectedNotePreview.text = "Selected Note: -"
                validateInputs()
            }
            .addOnFailureListener { e ->
                Toast.makeText(this, "Failed to load notes: ${e.message}", Toast.LENGTH_SHORT).show()
            }
    }

    private fun generateFlashcards() {
        if (isGenerating) return

        val topicText = etTopic.text.toString().trim()
        val note = selectedNote

        setGeneratingState(true)
        lifecycleScope.launch {
            try {
                val generated = withContext(Dispatchers.IO) {
                    if (selectedSource == SOURCE_TOPIC) {
                        flashcardGenerator.generateFromTopic(topicText, cardCount)
                    } else {
                        if (note == null) return@withContext emptyList()
                        val extractedText = downloadAndExtractText(note).take(12000)
                        if (extractedText.isBlank()) return@withContext emptyList()
                        flashcardGenerator.generateFromNotes(extractedText, cardCount)
                    }
                }

                if (generated.isEmpty()) {
                    Toast.makeText(
                        this@FlashcardSetupActivity,
                        "Could not generate flashcards. Please try again.",
                        Toast.LENGTH_LONG
                    ).show()
                    return@launch
                }

                val intent = Intent(this@FlashcardSetupActivity, FlashcardActivity::class.java).apply {
                    putExtra(EXTRA_SOURCE, selectedSource)
                    putExtra(EXTRA_TOPIC_TEXT, topicText)
                    putExtra(EXTRA_SELECTED_NOTE, note?.name.orEmpty())
                    putExtra(EXTRA_CARD_COUNT, generated.size)
                    putExtra(EXTRA_FLASHCARDS_JSON, Json.encodeToString(generated))
                }
                startActivity(intent)
            } catch (e: Exception) {
                Toast.makeText(
                    this@FlashcardSetupActivity,
                    "Could not generate flashcards. Please try again.",
                    Toast.LENGTH_LONG
                ).show()
            } finally {
                setGeneratingState(false)
            }
        }
    }

    private fun setGeneratingState(generating: Boolean) {
        isGenerating = generating
        cardTopic.isEnabled = !generating
        cardMyNotes.isEnabled = !generating
        etTopic.isEnabled = !generating
        spinnerNotes.isEnabled = !generating
        seekBarCards.isEnabled = !generating
        validateInputs()

        if (generating) {
            progressDialog.show()
        } else if (progressDialog.isShowing) {
            progressDialog.dismiss()
        }
    }

    private suspend fun downloadAndExtractText(note: NoteItem): String {
        val localFile = withContext(Dispatchers.IO) {
            val extension = note.name.substringAfterLast('.', "tmp")
            File.createTempFile("flashcard_note_", ".$extension", cacheDir)
        }

        return try {
            val downloaded = downloadNoteFile(note, localFile)
            if (!downloaded || localFile.length() == 0L) return ""
            when {
                note.name.endsWith(".pdf", ignoreCase = true) -> extractTextFromPdf(localFile)
                note.name.endsWith(".jpg", ignoreCase = true) ||
                    note.name.endsWith(".jpeg", ignoreCase = true) ||
                    note.name.endsWith(".png", ignoreCase = true) -> extractTextFromImage(localFile)
                else -> ""
            }
        } finally {
            localFile.delete()
        }
    }

    private suspend fun downloadNoteFile(note: NoteItem, destination: File): Boolean {
        return suspendCancellableCoroutine { continuation ->
            val fileRef = when {
                note.downloadUrl.isNotBlank() -> storage.getReferenceFromUrl(note.downloadUrl)
                else -> {
                    val uid = FirebaseAuth.getInstance().currentUser?.uid.orEmpty()
                    storage.reference.child("user_uploads/$uid/${note.name}")
                }
            }

            fileRef.getFile(destination)
                .addOnSuccessListener {
                    if (!continuation.isCompleted) continuation.resume(true)
                }
                .addOnFailureListener {
                    if (!continuation.isCompleted) continuation.resume(false)
                }
        }
    }

    private fun extractTextFromPdf(file: File): String {
        val document = PDDocument.load(file)
        return try {
            PDFTextStripper().getText(document)
        } catch (_: Exception) {
            ""
        } finally {
            document.close()
        }
    }

    private suspend fun extractTextFromImage(file: File): String {
        return suspendCancellableCoroutine { continuation ->
            val bitmap = BitmapFactory.decodeFile(file.absolutePath)
            if (bitmap == null) {
                continuation.resume("")
                return@suspendCancellableCoroutine
            }

            val image = InputImage.fromBitmap(bitmap, 0)
            val recognizer = TextRecognition.getClient(TextRecognizerOptions.DEFAULT_OPTIONS)

            recognizer.process(image)
                .addOnSuccessListener { text ->
                    if (!continuation.isCompleted) continuation.resume(text.text.orEmpty())
                }
                .addOnFailureListener {
                    if (!continuation.isCompleted) continuation.resume("")
                }
        }
    }

    data class NoteItem(
        val name: String,
        val type: String,
        val downloadUrl: String
    )

    companion object {
        const val SOURCE_TOPIC = "topic"
        const val SOURCE_NOTES = "notes"

        const val EXTRA_SOURCE = "source"
        const val EXTRA_TOPIC_TEXT = "topicText"
        const val EXTRA_SELECTED_NOTE = "selectedNote"
        const val EXTRA_CARD_COUNT = "cardCount"
        const val EXTRA_FLASHCARDS_JSON = "flashcardsJson"
    }
}

package com.example.aistudyassistance
import kotlinx.serialization.Serializable
@Serializable data class Flashcard( val question: String, val answer: String )

package com.example.aistudyassistance

import android.util.Log
import org.json.JSONArray
import org.json.JSONException

class FlashcardGenerator(private val geminiHelper: GeminiHelper) {

    companion object {
        private const val TAG = "FlashcardGenerator"
        private const val MAX_NOTE_CHARS = 12000
    }

    suspend fun generateFromTopic(topic: String, count: Int): List<Flashcard> {
        val prompt = """
            Generate $count flashcards for the topic "$topic".

            Rules:

            * Each flashcard must have:

              * a short question
              * a short answer (maximum 2 sentences)
            * Keep language simple and easy to understand
            * Do not include long paragraphs

            Return ONLY valid JSON in this exact format:

            [
            {
            "question": "Question text",
            "answer": "Short answer"
            }
            ]

            Important:

            * Do NOT include markdown
            * Do NOT include explanations outside JSON
            * Do NOT include extra text
        """.trimIndent()

        return generate(prompt)
    }

    suspend fun generateFromNotes(noteText: String, count: Int): List<Flashcard> {
        val limitedText = noteText.take(MAX_NOTE_CHARS)

        val prompt = """
            Generate $count flashcards using the following study material.

            Study Material:
            $limitedText

            Rules:

            * Each flashcard must contain a short question and a short answer (max 2 sentences)
            * Focus on key concepts and definitions
            * Return ONLY JSON in the specified format
            * No markdown
            * No extra text

            Return ONLY valid JSON in this exact format:

            [
            {
            "question": "Question text",
            "answer": "Short answer"
            }
            ]
        """.trimIndent()

        return generate(prompt)
    }

    private suspend fun generate(prompt: String): List<Flashcard> {
        return try {
            val response = geminiHelper.getResponse(prompt)
            parseFlashcardsJson(response)
        } catch (e: Exception) {
            Log.e(TAG, "Flashcard generation failed", e)
            emptyList()
        }
    }

    private fun parseFlashcardsJson(jsonString: String): List<Flashcard> {
        return try {
            val jsonArray = JSONArray(jsonString)
            val flashcards = mutableListOf<Flashcard>()

            for (i in 0 until jsonArray.length()) {
                val obj = jsonArray.optJSONObject(i) ?: continue
                val question = obj.optString("question", "").trim()
                val answer = obj.optString("answer", "").trim()

                if (question.isBlank() || answer.isBlank()) continue
                flashcards.add(Flashcard(question = question, answer = answer))
            }

            flashcards
        } catch (e: JSONException) {
            Log.e(TAG, "Invalid flashcard JSON", e)
            emptyList()
        }
    }
}

package com.example.aistudyassistance

import android.animation.Animator
import android.animation.AnimatorSet
import android.animation.ObjectAnimator
import android.animation.ValueAnimator
import android.content.res.ColorStateList
import android.view.animation.AccelerateDecelerateInterpolator
import android.view.animation.DecelerateInterpolator
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.TextView
import androidx.cardview.widget.CardView
import androidx.core.content.ContextCompat
import androidx.recyclerview.widget.RecyclerView
import com.google.android.material.button.MaterialButton

class FlashcardPagerAdapter(
    private val flashcards: List<Flashcard>,
    private val revealedStates: MutableList<Boolean>,
    private val difficultyStates: MutableList<Int>,
    private val onCardTapped: (Int) -> Unit,
    private val onDifficultyClicked: (Int, Int) -> Unit,
    private val onFlipStateChanged: (Int, Boolean) -> Unit
) : RecyclerView.Adapter<FlashcardPagerAdapter.FlashcardViewHolder>() {

    private val flippingPositions = mutableSetOf<Int>()

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): FlashcardViewHolder {
        val view = LayoutInflater.from(parent.context)
            .inflate(R.layout.item_flashcard_page, parent, false)
        return FlashcardViewHolder(view)
    }

    override fun onBindViewHolder(holder: FlashcardViewHolder, position: Int) {
        holder.bind(
            flashcard = flashcards[position],
            revealed = revealedStates[position],
            difficulty = difficultyStates[position],
            position = position,
            animateFlip = false
        )
    }

    override fun onBindViewHolder(
        holder: FlashcardViewHolder,
        position: Int,
        payloads: MutableList<Any>
    ) {
        if (payloads.isEmpty()) {
            super.onBindViewHolder(holder, position, payloads)
            return
        }

        val animateFlip = payloads.contains(PAYLOAD_FLIP)
        holder.bind(
            flashcard = flashcards[position],
            revealed = revealedStates[position],
            difficulty = difficultyStates[position],
            position = position,
            animateFlip = animateFlip
        )
    }

    override fun getItemCount(): Int = flashcards.size

    fun isCardFlipping(position: Int): Boolean = position in flippingPositions

    fun toggleRevealState(position: Int): Boolean {
        if (position !in revealedStates.indices || isCardFlipping(position)) return false
        revealedStates[position] = !revealedStates[position]
        notifyItemChanged(position, PAYLOAD_FLIP)
        return true
    }

    private fun markFlipping(position: Int, isFlipping: Boolean, holder: FlashcardViewHolder) {
        if (isFlipping) {
            flippingPositions.add(position)
        } else {
            flippingPositions.remove(position)
        }
        holder.cardFlashcard.isEnabled = !isFlipping
        onFlipStateChanged(position, isFlipping)
    }

    private fun showCardState(holder: FlashcardViewHolder, flashcard: Flashcard, revealed: Boolean) {
        holder.tvQuestion.text = flashcard.question
        holder.tvAnswer.text = flashcard.answer

        if (revealed) {
            stopHintPulse(holder.tvHint)
            holder.tvHint.visibility = View.GONE
            holder.tvAnswer.visibility = View.VISIBLE
            holder.layoutDifficulty.visibility = View.VISIBLE
        } else {
            holder.tvAnswer.visibility = View.GONE
            holder.layoutDifficulty.visibility = View.GONE
            holder.tvHint.visibility = View.VISIBLE
            startHintPulse(holder.tvHint)
        }
    }

    private fun applyDifficultyState(holder: FlashcardViewHolder, difficulty: Int) {
        val context = holder.itemView.context
        val buttons = listOf(holder.btnEasy, holder.btnMedium, holder.btnHard)

        buttons.forEach { button ->
            button.backgroundTintList = null
            button.alpha = 1f
            button.setTextColor(ContextCompat.getColor(context, R.color.text_main))
            button.isEnabled = difficulty == DIFFICULTY_NONE
        }

        if (difficulty in 0..2) {
            val selectedButton = buttons[difficulty]
            val selectedColor = when (difficulty) {
                DIFFICULTY_EASY -> ContextCompat.getColor(context, R.color.green)
                DIFFICULTY_MEDIUM -> ContextCompat.getColor(context, R.color.accent_orange)
                else -> ContextCompat.getColor(context, R.color.red)
            }

            selectedButton.backgroundTintList = ColorStateList.valueOf(selectedColor)
            selectedButton.alpha = 1f
            selectedButton.setTextColor(
                ContextCompat.getColor(
                    context,
                    if (difficulty == DIFFICULTY_MEDIUM) R.color.black else R.color.white
                )
            )

            buttons.forEachIndexed { index, button ->
                if (index != difficulty) {
                    button.alpha = 0.55f
                }
            }
        }
    }

    private fun startHintPulse(view: TextView) {
        stopHintPulse(view)
        val pulse = ObjectAnimator.ofFloat(view, View.ALPHA, 0.45f, 1f).apply {
            duration = 650
            repeatCount = ValueAnimator.INFINITE
            repeatMode = ValueAnimator.REVERSE
            interpolator = AccelerateDecelerateInterpolator()
        }
        view.tag = pulse
        pulse.start()
    }

    private fun stopHintPulse(view: TextView) {
        (view.tag as? ObjectAnimator)?.cancel()
        view.tag = null
        view.alpha = 1f
    }

    private fun flipCard(
        holder: FlashcardViewHolder,
        flashcard: Flashcard,
        revealed: Boolean,
        position: Int
    ) {
        val card = holder.cardFlashcard
        card.rotationY = 0f
        card.cameraDistance = card.resources.displayMetrics.density * 8000f

        val firstHalfRotation = ObjectAnimator.ofFloat(card, View.ROTATION_Y, 0f, 90f).apply {
            duration = 180
            interpolator = DecelerateInterpolator()
        }

        val firstHalfScaleX = ObjectAnimator.ofFloat(card, View.SCALE_X, 1f, 0.95f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val firstHalfScaleY = ObjectAnimator.ofFloat(card, View.SCALE_Y, 1f, 0.95f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val secondHalfRotation = ObjectAnimator.ofFloat(card, View.ROTATION_Y, -90f, 0f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val secondHalfScaleX = ObjectAnimator.ofFloat(card, View.SCALE_X, 0.95f, 1f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val secondHalfScaleY = ObjectAnimator.ofFloat(card, View.SCALE_Y, 0.95f, 1f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val firstHalf = AnimatorSet().apply {
            playTogether(firstHalfRotation, firstHalfScaleX, firstHalfScaleY)
        }

        val secondHalf = AnimatorSet().apply {
            playTogether(secondHalfRotation, secondHalfScaleX, secondHalfScaleY)
        }

        firstHalf.addListener(object : Animator.AnimatorListener {
            override fun onAnimationStart(animation: Animator) {
                markFlipping(position, true, holder)
            }

            override fun onAnimationEnd(animation: Animator) {
                showCardState(holder, flashcard, revealed)
            }

            override fun onAnimationCancel(animation: Animator) = Unit
            override fun onAnimationRepeat(animation: Animator) = Unit
        })

        AnimatorSet().apply {
            playSequentially(firstHalf, secondHalf)
            addListener(object : Animator.AnimatorListener {
                override fun onAnimationStart(animation: Animator) = Unit

                override fun onAnimationEnd(animation: Animator) {
                    markFlipping(position, false, holder)
                }

                override fun onAnimationCancel(animation: Animator) {
                    markFlipping(position, false, holder)
                }

                override fun onAnimationRepeat(animation: Animator) = Unit
            })
            start()
        }
    }

    inner class FlashcardViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) {
        val cardFlashcard: CardView = itemView.findViewById(R.id.cardFlashcard)
        private val tvQuestionTitle: TextView = itemView.findViewById(R.id.tvQuestionTitle)
        val tvQuestion: TextView = itemView.findViewById(R.id.tvQuestion)
        val tvHint: TextView = itemView.findViewById(R.id.tvTapHint)
        val tvAnswer: TextView = itemView.findViewById(R.id.tvAnswer)
        val layoutDifficulty: View = itemView.findViewById(R.id.layoutDifficulty)
        val btnEasy: MaterialButton = itemView.findViewById(R.id.btnEasy)
        val btnMedium: MaterialButton = itemView.findViewById(R.id.btnMedium)
        val btnHard: MaterialButton = itemView.findViewById(R.id.btnHard)

        fun bind(
            flashcard: Flashcard,
            revealed: Boolean,
            difficulty: Int,
            position: Int,
            animateFlip: Boolean
        ) {
            tvQuestionTitle.text = "Question"
            cardFlashcard.cameraDistance = itemView.resources.displayMetrics.density * 8000f
            cardFlashcard.setOnClickListener {
                if (!isCardFlipping(position)) {
                    onCardTapped(position)
                }
            }

            btnEasy.setOnClickListener { onDifficultySelected(position, DIFFICULTY_EASY) }
            btnMedium.setOnClickListener { onDifficultySelected(position, DIFFICULTY_MEDIUM) }
            btnHard.setOnClickListener { onDifficultySelected(position, DIFFICULTY_HARD) }

            applyDifficultyState(this, difficulty)

            if (animateFlip) {
                flipCard(this, flashcard, revealed, position)
            } else {
                cardFlashcard.rotationY = 0f
                cardFlashcard.scaleX = 1f
                cardFlashcard.scaleY = 1f
                markFlipping(position, false, this)
                showCardState(this, flashcard, revealed)
            }
        }

        private fun onDifficultySelected(position: Int, difficulty: Int) {
            if (position !in difficultyStates.indices) return
            if (difficultyStates[position] != DIFFICULTY_NONE) return

            difficultyStates[position] = difficulty
            notifyItemChanged(position)
            onDifficultyClicked(position, difficulty)
        }
    }

    companion object {
        const val DIFFICULTY_NONE = -1
        const val DIFFICULTY_EASY = 0
        const val DIFFICULTY_MEDIUM = 1
        const val DIFFICULTY_HARD = 2

        private const val PAYLOAD_FLIP = "payload_flip"
    }
}

package com.example.aistudyassistance

import android.animation.Animator
import android.animation.AnimatorSet
import android.animation.ObjectAnimator
import android.animation.ValueAnimator
import android.content.res.ColorStateList
import android.view.animation.AccelerateDecelerateInterpolator
import android.view.animation.DecelerateInterpolator
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.TextView
import androidx.cardview.widget.CardView
import androidx.core.content.ContextCompat
import androidx.recyclerview.widget.RecyclerView
import com.google.android.material.button.MaterialButton

class FlashcardPagerAdapter(
    private val flashcards: List<Flashcard>,
    private val revealedStates: MutableList<Boolean>,
    private val answerRevealedStates: MutableList<Boolean>,
    private val difficultyStates: MutableList<Int>,
    private val isActiveRecallEnabled: () -> Boolean,
    private val onCardTapped: (Int) -> Unit,
    private val onShowAnswerClicked: (Int) -> Unit,
    private val onDifficultyClicked: (Int, Int) -> Unit,
    private val onAnswerRevealed: (Int) -> Unit,
    private val onFlipStateChanged: (Int, Boolean) -> Unit
) : RecyclerView.Adapter<FlashcardPagerAdapter.FlashcardViewHolder>() {

    private val flippingPositions = mutableSetOf<Int>()

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): FlashcardViewHolder {
        val view = LayoutInflater.from(parent.context)
            .inflate(R.layout.item_flashcard_page, parent, false)
        return FlashcardViewHolder(view)
    }

    override fun onBindViewHolder(holder: FlashcardViewHolder, position: Int) {
        holder.bind(
            flashcard = flashcards[position],
            revealed = revealedStates[position],
            answerRevealed = answerRevealedStates[position],
            difficulty = difficultyStates[position],
            position = position,
            animateFlip = false,
            animateReveal = false
        )
    }

    override fun onBindViewHolder(
        holder: FlashcardViewHolder,
        position: Int,
        payloads: MutableList<Any>
    ) {
        if (payloads.isEmpty()) {
            super.onBindViewHolder(holder, position, payloads)
            return
        }

        val animateFlip = payloads.contains(PAYLOAD_FLIP)
        val animateReveal = payloads.contains(PAYLOAD_SHOW_ANSWER)
        holder.bind(
            flashcard = flashcards[position],
            revealed = revealedStates[position],
            answerRevealed = answerRevealedStates[position],
            difficulty = difficultyStates[position],
            position = position,
            animateFlip = animateFlip,
            animateReveal = animateReveal
        )
    }

    override fun getItemCount(): Int = flashcards.size

    fun isCardFlipping(position: Int): Boolean = position in flippingPositions

    fun toggleRevealState(position: Int): Boolean {
        if (position !in revealedStates.indices || isCardFlipping(position)) return false
        revealedStates[position] = !revealedStates[position]

        if (revealedStates[position] && !isActiveRecallEnabled()) {
            val wasRevealed = answerRevealedStates[position]
            answerRevealedStates[position] = true
            if (!wasRevealed) {
                onAnswerRevealed(position)
            }
        }

        notifyItemChanged(position, PAYLOAD_FLIP)
        return true
    }

    private fun markFlipping(position: Int, isFlipping: Boolean, holder: FlashcardViewHolder) {
        if (isFlipping) {
            flippingPositions.add(position)
        } else {
            flippingPositions.remove(position)
        }
        holder.cardFlashcard.isEnabled = !isFlipping
        onFlipStateChanged(position, isFlipping)
    }

    private fun showCardState(
        holder: FlashcardViewHolder,
        flashcard: Flashcard,
        revealed: Boolean,
        answerRevealed: Boolean
    ) {
        holder.tvQuestion.text = flashcard.question
        holder.tvAnswer.text = flashcard.answer

        val activeRecall = isActiveRecallEnabled()

        if (revealed) {
            stopHintPulse(holder.tvHint)
            holder.tvHint.visibility = View.GONE
            val shouldShowAnswer = !activeRecall || answerRevealed
            holder.tvThinkPrompt.visibility = if (activeRecall && !answerRevealed) View.VISIBLE else View.GONE
            holder.btnShowAnswer.visibility = if (activeRecall && !answerRevealed) View.VISIBLE else View.GONE
            holder.tvAnswer.visibility = if (shouldShowAnswer) View.VISIBLE else View.GONE
            holder.layoutDifficulty.visibility = if (shouldShowAnswer) View.VISIBLE else View.GONE
        } else {
            holder.tvThinkPrompt.visibility = View.GONE
            holder.btnShowAnswer.visibility = View.GONE
            holder.tvAnswer.visibility = View.GONE
            holder.layoutDifficulty.visibility = View.GONE
            holder.tvHint.visibility = View.VISIBLE
            startHintPulse(holder.tvHint)
        }
    }

    private fun animateAnswerReveal(holder: FlashcardViewHolder) {
        if (holder.tvAnswer.visibility != View.VISIBLE) return

        holder.tvAnswer.alpha = 0f
        holder.layoutDifficulty.alpha = 0f

        holder.tvAnswer.animate()
            .alpha(1f)
            .setDuration(220L)
            .start()

        holder.layoutDifficulty.animate()
            .alpha(1f)
            .setDuration(220L)
            .start()
    }

    private fun applyDifficultyState(holder: FlashcardViewHolder, difficulty: Int) {
        val context = holder.itemView.context
        val buttons = listOf(holder.btnEasy, holder.btnMedium, holder.btnHard)
        val defaultBg = ContextCompat.getColor(context, R.color.card_bg)
        val defaultText = ContextCompat.getColor(context, R.color.text_main)
        val defaultStroke = ContextCompat.getColor(context, R.color.divider)

        buttons.forEach { button ->
            button.backgroundTintList = ColorStateList.valueOf(defaultBg)
            button.strokeColor = ColorStateList.valueOf(defaultStroke)
            button.strokeWidth = 2
            button.alpha = 1f
            button.setTextColor(defaultText)
            button.isEnabled = difficulty == DIFFICULTY_NONE
        }

        if (difficulty in 0..2) {
            val selectedButton = buttons[difficulty]
            val selectedColor = when (difficulty) {
                DIFFICULTY_EASY -> ContextCompat.getColor(context, R.color.green)
                DIFFICULTY_MEDIUM -> ContextCompat.getColor(context, R.color.accent_orange)
                else -> ContextCompat.getColor(context, R.color.red)
            }

            selectedButton.backgroundTintList = ColorStateList.valueOf(selectedColor)
            selectedButton.strokeColor = ColorStateList.valueOf(selectedColor)
            selectedButton.alpha = 1f
            selectedButton.setTextColor(
                ContextCompat.getColor(
                    context,
                    if (difficulty == DIFFICULTY_MEDIUM) R.color.black else R.color.white
                )
            )

            buttons.forEachIndexed { index, button ->
                if (index != difficulty) {
                    button.alpha = 0.55f
                }
            }
        }
    }

    private fun startHintPulse(view: TextView) {
        stopHintPulse(view)
        val pulse = ObjectAnimator.ofFloat(view, View.ALPHA, 0.45f, 1f).apply {
            duration = 650
            repeatCount = ValueAnimator.INFINITE
            repeatMode = ValueAnimator.REVERSE
            interpolator = AccelerateDecelerateInterpolator()
        }
        view.tag = pulse
        pulse.start()
    }

    private fun stopHintPulse(view: TextView) {
        (view.tag as? ObjectAnimator)?.cancel()
        view.tag = null
        view.alpha = 1f
    }

    private fun flipCard(
        holder: FlashcardViewHolder,
        flashcard: Flashcard,
        revealed: Boolean,
        position: Int
    ) {
        val card = holder.cardFlashcard
        card.rotationY = 0f
        card.cameraDistance = card.resources.displayMetrics.density * 8000f

        val firstHalfRotation = ObjectAnimator.ofFloat(card, View.ROTATION_Y, 0f, 90f).apply {
            duration = 180
            interpolator = DecelerateInterpolator()
        }

        val firstHalfScaleX = ObjectAnimator.ofFloat(card, View.SCALE_X, 1f, 0.95f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val firstHalfScaleY = ObjectAnimator.ofFloat(card, View.SCALE_Y, 1f, 0.95f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val secondHalfRotation = ObjectAnimator.ofFloat(card, View.ROTATION_Y, -90f, 0f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val secondHalfScaleX = ObjectAnimator.ofFloat(card, View.SCALE_X, 0.95f, 1f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val secondHalfScaleY = ObjectAnimator.ofFloat(card, View.SCALE_Y, 0.95f, 1f).apply {
            duration = 180
            interpolator = AccelerateDecelerateInterpolator()
        }

        val firstHalf = AnimatorSet().apply {
            playTogether(firstHalfRotation, firstHalfScaleX, firstHalfScaleY)
        }

        val secondHalf = AnimatorSet().apply {
            playTogether(secondHalfRotation, secondHalfScaleX, secondHalfScaleY)
        }

        firstHalf.addListener(object : Animator.AnimatorListener {
            override fun onAnimationStart(animation: Animator) {
                markFlipping(position, true, holder)
            }

            override fun onAnimationEnd(animation: Animator) {
                val answerRevealed = answerRevealedStates.getOrElse(position) { false }
                showCardState(holder, flashcard, revealed, answerRevealed)
            }

            override fun onAnimationCancel(animation: Animator) = Unit
            override fun onAnimationRepeat(animation: Animator) = Unit
        })

        AnimatorSet().apply {
            playSequentially(firstHalf, secondHalf)
            addListener(object : Animator.AnimatorListener {
                override fun onAnimationStart(animation: Animator) = Unit

                override fun onAnimationEnd(animation: Animator) {
                    markFlipping(position, false, holder)
                }

                override fun onAnimationCancel(animation: Animator) {
                    markFlipping(position, false, holder)
                }

                override fun onAnimationRepeat(animation: Animator) = Unit
            })
            start()
        }
    }

    inner class FlashcardViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) {
        val cardFlashcard: CardView = itemView.findViewById(R.id.cardFlashcard)
        private val tvQuestionTitle: TextView = itemView.findViewById(R.id.tvQuestionTitle)
        val tvQuestion: TextView = itemView.findViewById(R.id.tvQuestion)
        val tvHint: TextView = itemView.findViewById(R.id.tvTapHint)
        val tvThinkPrompt: TextView = itemView.findViewById(R.id.tvThinkPrompt)
        val btnShowAnswer: MaterialButton = itemView.findViewById(R.id.btnShowAnswer)
        val tvAnswer: TextView = itemView.findViewById(R.id.tvAnswer)
        val layoutDifficulty: View = itemView.findViewById(R.id.layoutDifficulty)
        val btnEasy: MaterialButton = itemView.findViewById(R.id.btnEasy)
        val btnMedium: MaterialButton = itemView.findViewById(R.id.btnMedium)
        val btnHard: MaterialButton = itemView.findViewById(R.id.btnHard)

        fun bind(
            flashcard: Flashcard,
            revealed: Boolean,
            answerRevealed: Boolean,
            difficulty: Int,
            position: Int,
            animateFlip: Boolean,
            animateReveal: Boolean
        ) {
            tvQuestionTitle.text = "Question"
            cardFlashcard.cameraDistance = itemView.resources.displayMetrics.density * 8000f
            cardFlashcard.setOnClickListener {
                if (!isCardFlipping(position)) {
                    onCardTapped(position)
                }
            }

            btnShowAnswer.setOnClickListener {
                onShowAnswer(position)
            }
            btnShowAnswer.isEnabled = true
            btnShowAnswer.alpha = 1f

            btnEasy.setOnClickListener { onDifficultySelected(position, DIFFICULTY_EASY) }
            btnMedium.setOnClickListener { onDifficultySelected(position, DIFFICULTY_MEDIUM) }
            btnHard.setOnClickListener { onDifficultySelected(position, DIFFICULTY_HARD) }

            applyDifficultyState(this, difficulty)

            if (animateFlip) {
                flipCard(this, flashcard, revealed, position)
            } else {
                cardFlashcard.rotationY = 0f
                cardFlashcard.scaleX = 1f
                cardFlashcard.scaleY = 1f
                markFlipping(position, false, this)
                showCardState(this, flashcard, revealed, answerRevealed)
                if (animateReveal) {
                    animateAnswerReveal(this)
                }
            }
        }

        private fun onShowAnswer(position: Int) {
            if (position !in answerRevealedStates.indices) return
            if (!revealedStates[position]) return
            if (answerRevealedStates[position]) return

            btnShowAnswer.isEnabled = false
            btnShowAnswer.alpha = 0.65f
            itemView.postDelayed({
                if (position !in answerRevealedStates.indices) return@postDelayed
                if (answerRevealedStates[position]) return@postDelayed

                answerRevealedStates[position] = true
                onShowAnswerClicked(position)
                onAnswerRevealed(position)
                notifyItemChanged(position, PAYLOAD_SHOW_ANSWER)
            }, 350L)
        }

        private fun onDifficultySelected(position: Int, difficulty: Int) {
            if (position !in difficultyStates.indices) return
            if (position !in answerRevealedStates.indices || !answerRevealedStates[position]) return
            if (difficultyStates[position] != DIFFICULTY_NONE) return

            difficultyStates[position] = difficulty
            notifyItemChanged(position)
            onDifficultyClicked(position, difficulty)
        }
    }

    companion object {
        const val DIFFICULTY_NONE = -1
        const val DIFFICULTY_EASY = 0
        const val DIFFICULTY_MEDIUM = 1
        const val DIFFICULTY_HARD = 2

        private const val PAYLOAD_FLIP = "payload_flip"
